// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function getConditionVisual(condition: string): { icon: string; badgeVariant: 'primary' | 'secondary' | 'info' | 'warning' } {
  const normalized = condition.toLowerCase();
  if (normalized.includes('sun') || normalized.includes('clear')) {
    return { icon: '☀️', badgeVariant: 'warning' };
  }
  if (normalized.includes('cloud') || normalized.includes('overcast')) {
    return { icon: '☁️', badgeVariant: 'secondary' };
  }
  if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('shower')) {
    return { icon: '🌧️', badgeVariant: 'info' };
  }
  if (normalized.includes('storm') || normalized.includes('thunder')) {
    return { icon: '⛈️', badgeVariant: 'primary' };
  }
  if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('ice')) {
    return { icon: '❄️', badgeVariant: 'info' };
  }
  if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) {
    return { icon: '🌫️', badgeVariant: 'secondary' };
  }
  return { icon: '🌤️', badgeVariant: 'primary' };
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [isMetric, setIsMetric] = useState<boolean>(props.unit.toUpperCase() === 'C');
  const conditionVisual = useMemo(() => getConditionVisual(props.condition), [props.condition]);
  const forecastStatus = useMemo(() => {
    if (!Array.isArray(props.forecast)) {
      return { mode: 'invalid' as const, message: 'Forecast data is currently unavailable.' };
    }
    if (props.forecast.length < 5) {
      return { mode: 'warning' as const, message: `Expected 5 forecast days, received ${props.forecast.length}.` };
    }
    if (props.forecast.length > 5) {
      return { mode: 'warning' as const, message: `Received ${props.forecast.length} forecast days; showing the first 5.` };
    }
    return { mode: 'ok' as const, message: '' };
  }, [props.forecast]);
  const safeForecast = useMemo(() => {
    if (!Array.isArray(props.forecast)) {
      return [];
    }
    return props.forecast
      .slice(0, 5)
      .map((item, index) => ({
        day: item.day || `Day ${index + 1}`,
        icon: item.icon || '🌤️',
        high: typeof item.high === 'number' ? item.high : null,
        low: typeof item.low === 'number' ? item.low : null,
      }));
  }, [props.forecast]);
  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-6)"
        shadow="md"
        radius="xl"
      >
        <Stack gap="var(--ggui-spacing-6)">
          <Row justify="between" align="center" wrap>
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                {props.city}
              </Heading>
              <Row align="center" gap="var(--ggui-spacing-2)">
                <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                  {props.temperature}°{props.unit}
                </Text>
                <Text size="3xl" aria-label={`Current weather icon for ${props.condition}`}>
                  {conditionVisual.icon}
                </Text>
              </Row>
              <Badge variant={conditionVisual.badgeVariant}>{props.condition}</Badge>
            </Stack>

            <Stack gap="var(--ggui-spacing-2)">
              <Box
                padding="var(--ggui-spacing-2)"
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
              >
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Humidity
                </Text>
                <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  {props.humidity}%
                </Text>
              </Box>
              <Box
                padding="var(--ggui-spacing-2)"
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
              >
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Wind Speed
                </Text>
                <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  {props.windSpeed} {isMetric ? 'km/h' : 'mph'}
                </Text>
              </Box>
            </Stack>
          </Row>

          <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          <Stack gap="var(--ggui-spacing-2)">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              5-Day Forecast
            </Text>
            {forecastStatus.mode !== 'ok' ? (
              <Alert variant={forecastStatus.mode === 'invalid' ? 'info' : 'warning'} title="Forecast notice">
                {forecastStatus.message}
              </Alert>
            ) : null}
            {safeForecast.length === 0 ? (
              <Alert variant="info" title="No forecast available">
                Forecast data is currently unavailable.
              </Alert>
            ) : (
              <Row gap="var(--ggui-spacing-2)" wrap>
                {safeForecast.map((item, index) => (
                  <Box
                    key={`${item.day || 'day'}-${index}`}
                    padding="var(--ggui-spacing-2)"
                    background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                  >
                    <Stack align="center" gap="var(--ggui-spacing-1)">
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {item.day}
                      </Text>
                      <Text aria-label={`Forecast icon for ${item.day}`}>
                        {item.icon}
                      </Text>
                      <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                        {item.high === null || item.low === null ? '—' : `${item.high}°${props.unit} / ${item.low}°${props.unit}`}
                      </Text>
                    </Stack>
                  </Box>
                ))}
              </Row>
            )}
          </Stack>

          <Row justify="end">
            <Button
              variant="outline"
              onClick={() => setIsMetric((prev) => !prev)}
            >
              Display wind in {isMetric ? 'mph' : 'km/h'}
            </Button>
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

