// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };


const TOTAL_STEPS = 5;

const isValidEmail = (value: string): boolean => {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const [currentStep, setCurrentStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<string>('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [touchedName, setTouchedName] = useState<boolean>(false);
  const [touchedEmail, setTouchedEmail] = useState<boolean>(false);
  const [submitted, setSubmitted] = useState<boolean>(false);

  const safeSatisfactionLabels = useMemo(() => {
    return Array.isArray(props.satisfactionLabels) ? props.satisfactionLabels : [];
  }, [props.satisfactionLabels]);

  const safeFeatureOptions = useMemo(() => {
    return Array.isArray(props.featureOptions) ? props.featureOptions : [];
  }, [props.featureOptions]);

  const nameError = useMemo(() => {
    if (!touchedName && !submitted) return '';
    return name.trim() ? '' : 'Name is required.';
  }, [name, touchedName, submitted]);

  const emailError = useMemo(() => {
    if (!touchedEmail && !submitted) return '';
    if (!email.trim()) return 'Email is required.';
    if (!isValidEmail(email)) return 'Please enter a valid email address.';
    return '';
  }, [email, touchedEmail, submitted]);

  const stepValidity = useMemo(() => {
    const step1Valid = name.trim().length > 0 && isValidEmail(email);
    const step2Valid = satisfaction !== '';
    const step3Valid = true;
    const step4Valid = comments.length <= 500;
    const step5Valid = true;
    return { step1Valid, step2Valid, step3Valid, step4Valid, step5Valid };
  }, [name, email, satisfaction, comments]);

  const canGoNext = useMemo(() => {
    if (currentStep === 1) return stepValidity.step1Valid;
    if (currentStep === 2) return stepValidity.step2Valid;
    if (currentStep === 3) return stepValidity.step3Valid;
    if (currentStep === 4) return stepValidity.step4Valid;
    return stepValidity.step5Valid;
  }, [currentStep, stepValidity]);

  const progressValue = useMemo(() => {
    return (currentStep / TOTAL_STEPS) * 100;
  }, [currentStep]);

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const handleNext = useCallback(() => {
    if (currentStep === 1) {
      setTouchedName(true);
      setTouchedEmail(true);
    }
    if (!canGoNext) return;
    setCurrentStep((prev) => Math.min(TOTAL_STEPS, prev + 1));
  }, [currentStep, canGoNext]);

  const handleBack = useCallback(() => {
    setCurrentStep((prev) => Math.max(1, prev - 1));
  }, []);

  const handleSubmit = useCallback(() => {
    setSubmitted(true);
    setTouchedName(true);
    setTouchedEmail(true);
    if (!stepValidity.step1Valid || !stepValidity.step2Valid || !stepValidity.step4Valid) return;
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction),
      features,
      comments: comments.trim(),
    });
  }, [submit, name, email, satisfaction, features, comments, stepValidity]);
  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" radius="lg" shadow="sm" border>
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Survey Form</Heading>
              <Badge variant="primary">Step {currentStep} of {TOTAL_STEPS}</Badge>
            </Row>
            <Progress value={progressValue} max={100} variant="default" size="md" />
            <Divider margin="var(--ggui-spacing-2)" />

            {currentStep === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  placeholder="Enter your full name"
                  required
                  error={nameError || undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  placeholder="Enter your email address"
                  required
                  error={emailError || undefined}
                />
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  How satisfied are you?
                </Text>
                <RadioGroup
                  label="Satisfaction rating (1-5)"
                  value={satisfaction}
                  onChange={setSatisfaction}
                  options={safeSatisfactionLabels.map((item, index) => ({
                    value: String(index + 1),
                    label: `${index + 1} - ${item}`,
                  }))}
                  direction="vertical"
                />
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap="var(--ggui-spacing-3)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Which features interest you?
                </Text>
                {safeFeatureOptions.length === 0 ? (
                  <Alert variant="info" title="No feature options">
                    No features are currently available to select.
                  </Alert>
                ) : (
                  <Stack gap="var(--ggui-spacing-2)">
                    {safeFeatureOptions.map((feature) => (
                      <Checkbox
                        key={feature}
                        label={feature}
                        checked={features.includes(feature)}
                        onChange={(checked) => toggleFeature(feature, checked)}
                      />
                    ))}
                  </Stack>
                )}
              </Stack>
            )}

            {currentStep === 4 && (
              <Stack gap="var(--ggui-spacing-3)">
                <TextArea
                  label="Additional comments"
                  value={comments}
                  onChange={setComments}
                  placeholder="Share anything else you'd like us to know..."
                  rows={6}
                  maxLength={500}
                  showCount
                  helperText="Optional (max 500 characters)"
                />
              </Stack>
            )}

            {currentStep === 5 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review your answers</Heading>
                <Card padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant, #f4f4f5)" border radius="md" shadow="none">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text><Text is="span" weight="semibold">Name:</Text> {name || '—'}</Text>
                    <Text><Text is="span" weight="semibold">Email:</Text> {email || '—'}</Text>
                    <Text><Text is="span" weight="semibold">Satisfaction:</Text> {satisfaction || '—'}</Text>
                    <Text><Text is="span" weight="semibold">Features:</Text> {features.length ? features.join(', ') : 'None selected'}</Text>
                    <Text><Text is="span" weight="semibold">Comments:</Text> {comments.trim() || 'No comments provided'}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}

            <Divider margin="var(--ggui-spacing-2)" />
            <Row justify="between" align="center">
              <Button variant="ghost" onClick={handleBack} disabled={currentStep === 1}>
                Back
              </Button>
              {currentStep < TOTAL_STEPS ? (
                <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>
                  Next
                </Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit}>
                  Submit
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

