                                  <Button size="sm" onClick={() => saveEditTask(task.id || '')}>Save</Button>
                                  <Button size="sm" variant="ghost" onClick={() => setEditingTaskId('')}>Cancel</Button>
                                </Row>
                              ) : (
                                <Row justify="between" align="center" gap="var(--ggui-spacing-2)">
                                  <Text as={Clickable} onDoubleClick={() => startEditTask(task.id || '', task.title)}>{task.title || 'Untitled task'}</Text>
                                  <Button size="xs" variant="ghost" onClick={() => startEditTask(task.id || '', task.title)}>Edit</Button>
                                </Row>
                              )}
                              <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                                <Badge variant={getPriorityBadgeVariant(task.priority)}>{task.priority || 'low'}</Badge>
                                <Avatar name={getInitials(task.assignee)} size="xs" />
                                {task.dueDate ? <Text variant="caption">Due: {task.dueDate}</Text> : null}
                              </Row>
                              <Select
                                label="Move task"
                                value={task.column || 'todo'}
