                              />
                            </Stack>
                          </Card>
                        ))
                      )}
                    </Stack>

                    {showAddForm[columnId] ? (
                      <Card padding="var(--ggui-spacing-3)" border shadow="none">
                        <Stack gap="var(--ggui-spacing-2)">
                          <Input
                            label="Task title"
                            value={newTaskByColumn[columnId]?.title || ''}
                            onChange={(value) => setNewTaskByColumn((prev) => ({ ...prev, [columnId]: { title: value, priority: prev[columnId]?.priority || 'medium' } }))}
                            placeholder="Enter task title"
                          />
                          <Select
                            label="Priority"
                            value={newTaskByColumn[columnId]?.priority || 'medium'}
