                          </Row>
                        </Stack>
                      </Card>
                    ) : (
                      <Button variant="outline" onClick={() => setShowAddForm((prev) => ({ ...prev, [columnId]: true }))}>Add Task</Button>
                    )}
                  </Stack>
                </Card>
              );
            })}
          </Row>
        )}

        {!isLoading && tasks.length === 0 ? (
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">No tasks yet</Text>
        ) : null}
      </Stack>
    </Container>

  );
}

