}

const CATEGORY_COLORS: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-100, #fee2e2)',
  'alkaline earth metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'transition metal': 'var(--ggui-color-primary-100, #e0f2fe)',
  lanthanide: 'var(--ggui-color-success-100, #dcfce7)',
  actinide: 'var(--ggui-color-success-100, #dcfce7)',
  metalloid: 'var(--ggui-color-info-100, #cffafe)',
  'post-transition metal': 'var(--ggui-color-primary-50, #f0f9ff)',
  nonmetal: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
  halogen: 'var(--ggui-color-warning-100, #fef3c7)',
  'noble gas': 'var(--ggui-color-primary-200, #bae6fd)',
  'noble-gas': 'var(--ggui-color-primary-200, #bae6fd)',
  unknown: 'var(--ggui-color-outlineVariant, #e4e4e7)',
};

function normalizeCategory(category?: string): string {
  return (category ?? 'unknown').trim().toLowerCase();
}

function getCategoryColor(category?: string): string {
  const key = normalizeCategory(category);
  return CATEGORY_COLORS[key] ?? 'var(--ggui-color-surfaceVariant, #f4f4f5)';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [searchValue, setSearchValue] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);
  const matchingAtomicNumbers = useMemo(() => {
    const source = Array.isArray(props.elements) ? props.elements : [];
    const query = searchValue.trim().toLowerCase();
    if (!query) {
      return new Set<number>();
    }
    return new Set(
      source
        .filter((element) => {
          const name = (element.name ?? '').toLowerCase();
          const symbol = (element.symbol ?? '').toLowerCase();
          return name.includes(query) || symbol.includes(query);
        })
        .map((element) => element.atomicNumber)
        .filter((atomicNumber): atomicNumber is number => typeof atomicNumber === 'number')
    );
  }, [props.elements, searchValue]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    const source = Array.isArray(props.elements) ? props.elements : [];
    source.forEach((element) => set.add(normalizeCategory(element.category)));
    return Array.from(set).sort((a, b) => a.localeCompare(b));
  }, [props.elements]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) {
      return null;
    }
    const source = Array.isArray(props.elements) ? props.elements : [];
    return source.find((element) => element.atomicNumber === selectedAtomicNumber) ?? null;
  }, [props.elements, selectedAtomicNumber]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={2}>Interactive Periodic Table</Heading>
        <Input
          label="Search elements"
          placeholder="Search by element name or symbol"
          value={searchValue}
          onChange={setSearchValue}
        />

        {searchValue.trim() !== '' && matchingAtomicNumbers.size === 0 && (
          <Alert variant="info" title="No matching elements">
            Try a different name or symbol.
          </Alert>
        )}
        <Box
          padding="var(--ggui-spacing-4)"
          background="var(--ggui-color-surfaceVariant, #f4f4f5)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
        >
          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
              gap: 'var(--ggui-spacing-2)',
            }}
          >
            {(Array.isArray(props.elements) ? props.elements : []).map((element, index) => {
              const atomicNumber = element.atomicNumber ?? index;
              const isSelected = selectedAtomicNumber === (element.atomicNumber ?? null);
              const hasQuery = searchValue.trim() !== '';
              const isMatch =
                !hasQuery ||
                (typeof element.atomicNumber === 'number' && matchingAtomicNumbers.has(element.atomicNumber));
              return (
                <Card
                  key={`${element.atomicNumber ?? 'x'}-${element.symbol ?? 'u'}-${index}`}
                  as={Clickable}
                  onClick={() => setSelectedAtomicNumber(element.atomicNumber ?? null)}
                  padding="var(--ggui-spacing-2)"
                  border
                  shadow="none"
                  radius="md"
                  style={{
                    minHeight: '72px',
                    position: 'relative',
                    gridColumn: `${element.col ?? 1}`,
                    gridRow: `${element.row ?? 1}`,
                    background: getCategoryColor(element.category),
                    borderColor: isSelected
                      ? 'var(--ggui-color-primary-600, #0284c7)'
                      : 'var(--ggui-color-outlineVariant, #e4e4e7)',
                    opacity: isMatch ? 1 : 0.18,
                  }}
                >
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    is="span"
                    style={{ position: 'absolute', top: 'var(--ggui-spacing-1)', left: 'var(--ggui-spacing-1)' }}
                  >
                    {atomicNumber}
                  </Text>
                  <Stack align="center" justify="center" style={{ height: '100%' }}>
                    <Text size="xl" weight="bold" align="center">
                      {element.symbol ?? '-'}
                    </Text>
                  </Stack>
                </Card>
              );
            })}
          </Box>
        </Box>

        <Card padding="var(--ggui-spacing-4)" border shadow="sm" radius="lg">
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={4}>Element Details</Heading>
            {selectedElement ? (
              <Stack gap="var(--ggui-spacing-1)">
                <Text><Text is="span" weight="semibold">Name:</Text> {selectedElement.name ?? 'N/A'}</Text>
                <Text><Text is="span" weight="semibold">Symbol:</Text> {selectedElement.symbol ?? 'N/A'}</Text>
                <Text><Text is="span" weight="semibold">Atomic Number:</Text> {selectedElement.atomicNumber ?? 'N/A'}</Text>
                <Text><Text is="span" weight="semibold">Atomic Weight:</Text> {selectedElement.atomicWeight ?? 'N/A'}</Text>
                <Text><Text is="span" weight="semibold">Category:</Text> {selectedElement.category ?? 'N/A'}</Text>
              </Stack>
            ) : (
              <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">Click an element to view details.</Text>
            )}
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4)" border shadow="sm" radius="lg">
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={5}>Legend</Heading>
            <Row style={{ display: 'flex', flexWrap: 'wrap', gap: 'var(--ggui-spacing-2)' }}>
              {categories.map((category) => (
