export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [messageText, setMessageText] = useState<string>('');
  const [allMessages, setAllMessages] = useState<ChatMessageItem[]>(() =>
    (props.messages || []).map((item) => ({
      sender: item.sender || 'Unknown',
      text: item.text || '',
      timestamp: item.timestamp || new Date().toISOString(),
    })),
  );
  const messagesContainerRef = useRef<HTMLDivElement | null>(null);
  const hasAutoScrolledInitiallyRef = useRef<boolean>(false);
  const shouldForceScrollRef = useRef<boolean>(false);

  useEffect(() => {
    setAllMessages(
      (props.messages || []).map((item) => ({
        sender: item.sender || 'Unknown',
        text: item.text || '',
        timestamp: item.timestamp || new Date().toISOString(),
      })),
    );
  }, [props.messages]);

  useEffect(() => {
    if (!message.latest) {
      return;
    }
    setAllMessages((prev) => [
      ...prev,
      {
        sender: message.latest.sender || 'Unknown',
        text: message.latest.text || '',
        timestamp: message.latest.timestamp || new Date().toISOString(),
      },
    ]);
  }, [message.latest]);

  useEffect(() => {
    const container = messagesContainerRef.current;
    if (!container) {
      return;
    }

    const distanceFromBottom = container.scrollHeight - container.scrollTop - container.clientHeight;
    const isNearBottom = distanceFromBottom <= 80;
    const shouldScroll = !hasAutoScrolledInitiallyRef.current || shouldForceScrollRef.current || isNearBottom;

    if (shouldScroll) {
      container.scrollTop = container.scrollHeight;
      hasAutoScrolledInitiallyRef.current = true;
    }

    shouldForceScrollRef.current = false;
  }, [allMessages]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender: string; messages: ChatMessageItem[]; isOwn: boolean }> = [];
    allMessages.forEach((msg) => {
      const isOwn = msg.sender === props.currentUser;
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.messages.push(msg);
      } else {
        groups.push({ sender: msg.sender, messages: [msg], isOwn });
      }
    });
    return groups;
  }, [allMessages, props.currentUser]);

  const typingLabel = useMemo(() => {
    if (!typing.latest?.active) {
      return '';
    }
    if (!typing.latest.sender || typing.latest.sender === props.currentUser) {
      return '';
    }
    return `${typing.latest.sender} is typing...`;
  }, [typing.latest, props.currentUser]);

  const formatTime = useCallback((value: string) => {
