              borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            }}
          >
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">{props.title}</Heading>
              {typingLabel ? (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{typingLabel}</Text>
              ) : (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {' '}
                </Text>
              )}
            </Stack>
            <Badge variant="primary">{props.participantCount} participants</Badge>
          </Row>

          <Box
            ref={messagesContainerRef}
            padding="var(--ggui-spacing-4)"
            style={{
              background: 'var(--ggui-color-surface, #fafafa)',
              height: '60vh',
              overflowY: 'auto',
            }}
          >
            {groupedMessages.length === 0 ? (
              <Text align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No messages yet
              </Text>
            ) : (
              <Stack gap="var(--ggui-spacing-4)">
                {groupedMessages.map((group, groupIndex) => (
                  <Stack
                    key={`${group.sender}-${groupIndex}`}
                    gap="var(--ggui-spacing-1)"
                    align={group.isOwn ? 'end' : 'start'}
                  >
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {group.sender}
                    </Text>
                    {group.messages.map((msg, msgIndex) => (
                      <Box
                        key={`${group.sender}-${groupIndex}-${msg.timestamp}-${msgIndex}`}
                        padding="var(--ggui-spacing-2)"
                        borderRadius="var(--ggui-shape-radius-md, 8px)"
                        background={
                          group.isOwn
                            ? 'var(--ggui-color-primary-600, #0284c7)'
                            : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                        }
                        style={{ maxWidth: '75%' }}
                      >
                        <Stack gap="var(--ggui-spacing-1)">
                          <Text
                            variant="bodySmall"
                            color={
                              group.isOwn
                                ? 'var(--ggui-color-surface, #fafafa)'
                                : 'var(--ggui-color-onSurface, #18181b)'
                            }
                          >
                            {msg.text}
                          </Text>
                          <Text
                            variant="caption"
                            align="right"
                            color={
                              group.isOwn
                                ? 'var(--ggui-color-primary-100, #e0f2fe)'
                                : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                            }
                          >
                            {formatTime(msg.timestamp)}
                          </Text>
                        </Stack>
                      </Box>
                    ))}
                  </Stack>
                ))}
                <Box />
              </Stack>
            )}
          </Box>


          <Divider margin="0" />

          <Row
            align="end"
            gap="var(--ggui-spacing-2)"
            style={{
              padding: 'var(--ggui-spacing-4, 16px)',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
          >
            <Box style={{ flex: 1 }}>
              <Input
                label="Message"
                placeholder="Type your message..."
                value={messageText}
                onChange={setMessageText}
                onKeyDown={handleInputKeyDown}
              />
            </Box>
            <Button variant="primary" onClick={handleSend} disabled={!messageText.trim()}>
              Send
            </Button>
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

