              No stocks available.
            </Text>
          </Card>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {displayStocks.map((stock, index) => {
              const isPositive = (stock.change ?? 0) >= 0;
              const symbol = stock.symbol ?? `stock-${index}`;
              const isHighlighted = highlightedSymbols[symbol];

              return (
                <Card
                  key={symbol}
                  padding="var(--ggui-spacing-6)"
                  radius="lg"
                  border
                  shadow="sm"
                  style={{
                    borderColor: isPositive
                      ? 'var(--ggui-color-success, #16a34a)'
                      : 'var(--ggui-color-error, #dc2626)',
                    borderWidth: '1px',
                    borderStyle: 'solid',
                  }}
                >
                  <Box
                    padding="var(--ggui-spacing-4)"
                    background={isHighlighted ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                  >
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text size="3xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                        {stock.symbol ?? '—'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {stock.name ?? 'Unknown Company'}
                      </Text>
                      <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                        ${(stock.price ?? 0).toFixed(2)}
                      </Heading>
                      <Row align="center" gap="var(--ggui-spacing-2)">
                        <Text
                          variant="label"
                          color={isPositive ? 'var(--ggui-color-success, #16a34a)' : 'var(--ggui-color-error, #dc2626)'}
                        >
                          {(stock.change ?? 0) >= 0 ? '+' : ''}{(stock.change ?? 0).toFixed(2)}
                        </Text>
                        <Text
                          variant="label"
                          color={isPositive ? 'var(--ggui-color-success, #16a34a)' : 'var(--ggui-color-error, #dc2626)'}
                        >
                          {isPositive ? '▲' : '▼'} {Math.abs(stock.changePercent ?? 0).toFixed(2)}%
                        </Text>
