  const safeAvatarOptions = useMemo(() => {
    if (props.avatarOptions.length >= 4) return props.avatarOptions.slice(0, 4);
    const fallback = ['😀', '😎', '🧠', '🚀'];
    const merged = [...props.avatarOptions];
    fallback.forEach((item) => {
      if (merged.length < 4 && !merged.includes(item)) merged.push(item);
    });
    return merged.slice(0, 4);
