                        padding="var(--ggui-spacing-2)"
                        border
                        radius="md"
                        shadow="none"
                        hoverStyle={{ opacity: 0.9 }}
                        style={{
                          background:
                            avatar === option
                              ? 'var(--ggui-color-primary-100, #e0f2fe)'
                              : 'var(--ggui-color-surface, #fafafa)',
                          borderColor:
                            avatar === option
                              ? 'var(--ggui-color-primary-600, #0284c7)'
                              : 'var(--ggui-color-outline, #d4d4d8)',
                        }}
                      >
                        <Text size="2xl" align="center">
                          {option}
                        </Text>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select role"
                  options={props.roleOptions.map((option) => ({
                    value: option,
                    label: option,
                  }))}
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label="Theme preference (dark mode)"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review & Confirm</Heading>
                <Alert variant="info" title="Please review your details">
                  You can go back to edit any field before completing setup.
                </Alert>
                <Card
                  padding="var(--ggui-spacing-4)"
                  border
                  shadow="none"
                  radius="md"
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text><strong>Name:</strong> {name || '—'}</Text>
                    <Text><strong>Email:</strong> {email || '—'}</Text>
                    <Text><strong>Avatar:</strong> {avatar || '—'}</Text>
                    <Text><strong>Role:</strong> {role || '—'}</Text>
                    <Text><strong>Email Notifications:</strong> {emailNotifications ? 'On' : 'Off'}</Text>
                    <Text><strong>Theme:</strong> {theme}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>

          <Divider margin="var(--ggui-spacing-4)" />

          <Row justify="between" align="center">
            <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
              {step === 3 ? 'Go Back' : 'Back'}
            </Button>
            <Row gap="var(--ggui-spacing-2)">
              {step < 3 && (
                <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>
                  Next
                </Button>
              )}
              {step === 3 && (
                <Button variant="primary" onClick={handleComplete} disabled={!canGoNext}>
                  Complete Setup
                </Button>
              )}
            </Row>
          </Row>
        </Card>
      </Stack>
    </Container>

  );
}
